40	const PROCESSING_FEE = 5;
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const LOYALTY_DISCOUNT_RATE = 0.2;
47	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
48	const COMPONENT_BLOCK_SIZE = 3;
49	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
50	const DEDUCTIBLE = 100;
51	const CAP_MULTIPLIER = 2;
52	
53	const BASE_PREMIUMS: Record<string, number> = {
54	  sword: 100,
55	  amulet: 60,
56	  staff: 80,
57	  potion: 40,
58	  rune: 25,
59	  moonstone: 25,
60	};
61	
62	const INSURANCE_VALUES: Record<string, number> = {
63	  sword: 1000,
64	  rune: 250,
65	};
66	
67	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
68	
69	const isComponentBlock = (type: string, count: number): boolean =>
70	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
71	
72	const basePremiumFor = (type: string): number => {
73	  const basePremium = BASE_PREMIUMS[type];
74	  if (basePremium === undefined) {
75	    throw new Error(`Unknown item type: ${type}`);
76	  }
77	  return basePremium;
78	};
79	
80	const surchargeFor = (
81	  items: Item[],
82	  applies: (item: Item) => boolean,
83	  rate: number
84	): number =>
85	  items.reduce(
86	    (surcharge, item) =>
87	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
88	    0
89	  );
90	
91	const isCursed = (item: Item): boolean => item.cursed === true;
92	
93	const isHighlyEnchanted = (item: Item): boolean =>
94	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
95	
96	const curseSurchargeFor = (items: Item[]): number =>
97	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
98	
99	const enchantmentSurchargeFor = (items: Item[]): number =>
100	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
101	
102	const groupBasePremium = (type: string, count: number): number =>
103	  isComponentBlock(type, count)
104	    ? COMPONENT_BLOCK_BASE_PREMIUM
105	    : count * basePremiumFor(type);
106	
107	const policyBaseFor = (items: Item[]): number => {
108	  const countsByType = new Map<string, number>();
109	  for (const item of items) {
110	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
111	  }
112	
113	  let policyBase = 0;
114	  for (const [type, count] of countsByType) {
115	    policyBase += groupBasePremium(type, count);
116	  }
117	  return policyBase;
118	};
119	
120	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
121	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
122	
123	const quotePremium = (
124	  items: Item[],
125	  customer: Customer,
126	  isFollowUp: boolean
127	): number => {
128	  const policyBase = policyBaseFor(items);
129	  const itemSurcharges =
130	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
131	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
132	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
133	    ? policyBase * LOYALTY_DISCOUNT_RATE
134	    : 0;
135	  const followUpDiscount = isFollowUp
136	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
137	    : 0;
138	  return Math.ceil(
139	    policyBase +
140	      itemSurcharges +
141	      firstInsuranceSurcharge -
142	      loyaltyDiscount -
143	      followUpDiscount +
144	      PROCESSING_FEE
145	  );
146	};
147	
148	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
149	
150	const insuranceSumFor = (items: Item[]): number =>
151	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
152	
153	const processClaim = (step: Step, steps: Step[]): unknown => {
154	  const policyItems = steps[step.policy!].items ?? [];
155	  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
156	  const payout = step.incident!.damages[0].amount - DEDUCTIBLE;
157	  return { payout, remainingCap: payoutCap - payout };
158	};
159	
160	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
161	  const results = input.steps.map((step, index) =>
162	    step.op === "claim"
163	      ? processClaim(step, input.steps)
164	      : {
165	          premium: quotePremium(
166	            step.items ?? [],
167	            input.customer,
168	            isFollowUpQuote(index)
169	          ),
170	        }
171	  );
172	  return { results };
173	};
